insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:4-3-exchange-rates:match:21ff1422', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Supply of pounds”?", "options": ["Comes from UK buyers of imports, UK investors abroad, and speculators expecting the pound to fall", "The price of one currency expressed in terms of another", "A deliberate fall in a currency''s value under a FIXED exchange rate system", "Buying or selling a currency in anticipation of its future value changing"]}'::jsonb, '{"answer": 0, "explain": "“Supply of pounds” means: Comes from UK buyers of imports, UK investors abroad, and speculators expecting the pound to fall"}'::jsonb),
('economics:4-3-exchange-rates:match:6e5e0ddb', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Speculation (currency)”?", "options": ["Buying or selling a currency in anticipation of its future value changing", "A system where the currency''s value is set purely by demand and supply on foreign exchange markets", "A good or service sold to another country, causing an inflow of money", "A deliberate fall in a currency''s value under a FIXED exchange rate system"]}'::jsonb, '{"answer": 0, "explain": "“Speculation (currency)” means: Buying or selling a currency in anticipation of its future value changing"}'::jsonb),
('economics:4-3-exchange-rates:match:0caa54c2', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Current account”?", "options": ["A system where the currency''s value is set purely by demand and supply on foreign exchange markets", "A good or service bought from another country, causing an outflow of money", "A rise in the value of a currency relative to another", "The record of a country''s trade in goods and services, plus income and transfers, with the rest of the world"]}'::jsonb, '{"answer": 3, "explain": "“Current account” means: The record of a country''s trade in goods and services, plus income and transfers, with the rest of the world"}'::jsonb),
('economics:4-3-exchange-rates:match:55bbc844', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Import”?", "options": ["A deliberate fall in a currency''s value under a FIXED exchange rate system", "A good or service bought from another country, causing an outflow of money", "The price of one currency expressed in terms of another", "A deliberate rise in a currency''s value under a FIXED exchange rate system"]}'::jsonb, '{"answer": 1, "explain": "“Import” means: A good or service bought from another country, causing an outflow of money"}'::jsonb),
('economics:4-3-exchange-rates:match:82989d82', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Export”?", "options": ["A good or service sold to another country, causing an inflow of money", "The record of a country''s trade in goods and services, plus income and transfers, with the rest of the world", "Comes from UK buyers of imports, UK investors abroad, and speculators expecting the pound to fall", "Comes from overseas buyers of UK exports, foreign investors, and speculators expecting the pound to rise"]}'::jsonb, '{"answer": 0, "explain": "“Export” means: A good or service sold to another country, causing an inflow of money"}'::jsonb),
('economics:4-3-exchange-rates:match:3c522305', 'economics', 'economics:4-3-exchange-rates', '4.3 Exchange Rates', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price elasticity of demand (trade)”?", "options": ["How much the quantity of exports/imports demanded responds to a price change caused by the exchange rate", "The record of a country''s trade in goods and services, plus income and transfers, with the rest of the world", "Buying or selling a currency in anticipation of its future value changing", "A deliberate rise in a currency''s value under a FIXED exchange rate system"]}'::jsonb, '{"answer": 0, "explain": "“Price elasticity of demand (trade)” means: How much the quantity of exports/imports demanded responds to a price change caused by the exchange rate"}'::jsonb),
('economics:4-4-globalisation:exam:a3f36849', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q3", "question": "What is the most likely cost of globalisation for consumers in developed countries?", "options": ["Dominant global brands", "Higher prices", "Increased immigration", "Lower prices"], "hint": "⚠️ Documented misconception: candidates often pick ''increased immigration'', but that''s a labour-market issue, not a direct cost for consumers. Think about what happens to variety and local shops when big global brands take over.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Dominant global brands</strong></p>\n<ul>\n<li>Dominant global brands out-compete smaller local firms, reducing genuine variety for consumers (homogenisation). Globalisation tends to LOWER prices (D is the opposite of a cost), and higher prices (B) is not the most likely effect described here.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A common misconception was that increased immigration was a cost of globalisation, rather than the more likely negative impact of dominant global brands (A).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:085a9ce8', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Why can the life expectancy of the population be used to help measure the development of a country?", "options": ["A larger number of people need to be educated so more teachers are required", "An improved life expectancy will encourage parents to have fewer children", "If people live longer there will be greater demand for health services", "It can help to indicate safety levels in a country are higher due to less conflict"], "hint": "Life expectancy reflects underlying quality-of-life factors — including how safe and stable a country is. Think about what a longer average lifespan implies about the conditions people are living in, not just what it later causes.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — It can help to indicate safety levels in a country are higher due to less conflict</strong></p>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered D correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:4c88ce36', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q5", "question": "In the past 20 years there has been more free movement of goods and greater international interdependence. What is this called?", "options": ["Globalisation", "International trade", "Specialisation", "Sustainability"], "hint": "This is the exact textbook definition of globalisation — free movement of goods PLUS greater interdependence between countries.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Globalisation</strong></p>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered A correctly, although a relatively small proportion of candidates selected B. It is worth learning definitions fully.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:f2e02b26', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q6", "question": "How is this an example of social sustainability?", "options": ["Residents of Manaus will have shorter travel times when visiting friends", "Road repairs will be less expensive for the government in the future", "The firms rebuilding the road will pay increased levels of taxation", "Vehicles will use less fuel as the roads are easier to drive on"], "caseStudy": "<p>Permission was granted in 2022 for a major road to be rebuilt in Brazil''s Amazon rainforest. The rebuilt road will help the residents of the largest Amazon city, Manaus, to stay connected to the rest of Brazil throughout the year.</p>", "hint": "⚠️ Social sustainability is about people''s quality of life and social connections — not government costs, tax revenue or fuel use (those are economic/environmental, not social).", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Residents of Manaus will have shorter travel times when visiting friends</strong></p>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered A correctly, although a reasonably common misconception was selecting D, which is not an example of social sustainability.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:2c328359', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Which of the following effects would have an impact on the environmental sustainability of the country?", "options": ["Greater competition from other countries", "Increased unemployment in other industries", "Overuse of scarce resources", "Reduction in choice for consumers"], "caseStudy": "<p>As a result of globalisation, a less developed country has specialised in copper mining.</p>", "hint": "Environmental sustainability is about whether resource use can continue long-term. Copper is a finite resource — what happens if mining uses it up faster than it can be replaced or managed?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Overuse of scarce resources</strong></p>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:9866a024', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q9", "question": "Which of the following has been a driving factor of globalisation?", "options": ["Better communications", "Greater environmental damage", "Higher taxation on imports", "Increased transport costs"], "hint": "Only one option would actually make trading internationally easier and cheaper — the other three would all discourage or slow down globalisation.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: A — Better communications</strong></p>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:db94ef31', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Which of the following is most likely to be a benefit of globalisation to producers in developed countries?", "options": ["A fall in unemployment", "Higher environmental standards", "Increased competition", "Lower wage rates"], "hint": "Think from the PRODUCER''s point of view, not the worker''s — a lower cost of a key input (labour) is a benefit to a firm''s costs, even though it may be a cost for workers. The other three options all lead to a likely COST for producers.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Lower wage rates</strong></p>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A majority of candidates gave Option D as the correct response to this question. The distractors here all lead to a likely cost for producers.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:964c5bb8', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q11", "question": "One of the driving factors of globalisation is improvements in transportation. Which of the following explains this driving factor?", "options": ["Container ships have reduced average costs", "Improved environmental sustainability", "Increased use of call centres", "Lower tariff barriers on imports"], "hint": "Focus specifically on TRANSPORT — call centres are a communications example, and tariffs are a trade-policy example, not a transport one.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Container ships have reduced average costs</strong></p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:977c915b', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q12", "question": "Which of the following is a cost of development for workers in a less developed country?", "options": ["Increased foreign investment", "Increased use of machinery", "Less choice of domestic brands", "Migration of skilled workers"], "hint": "Think about automation replacing manual labour as an economy develops — which option directly threatens WORKERS'' jobs, rather than being a benefit or a consumer-side effect?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Increased use of machinery</strong></p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:3dc37f03', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Increased GDP per capita is used to show improved development of a country because", "options": ["it means there will no longer be any need for state provision", "markets will have become more competitive", "more opportunities for work are likely to exist", "no other measure of development is available"], "hint": "Rising average income is generally linked to a growing economy creating jobs. Watch the extreme wording in the other options (''no longer be any need'', ''no other measure available'') — these overstate the case and are usually wrong on GCSE MCQs.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — more opportunities for work are likely to exist</strong></p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:ebda43ac', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q16", "question": "Which of the following is likely to be the greatest benefit of globalisation to consumers in less developed countries?", "options": ["A better infrastructure", "A wider range of resources", "Increased migration opportunities", "Increased use of technology"], "hint": "Think about what foreign investment typically brings first to a less developed country''s consumers, alongside the goods themselves — roads, rail and other capital projects that improve everyday access to markets.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — A better infrastructure</strong></p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:exam:af431001', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'exam', 'mcq', 1, '{"num": "Q20", "question": "Which one of the following is a method of measuring development?", "options": ["Cost of living", "Environmental sustainability", "Life expectancy", "Nominal income"], "hint": "Nominal income is not adjusted for prices or population, and cost of living/environmental sustainability are related but different concepts. Which option is a direct, named component of the HDI?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — Life expectancy</strong></p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-4-globalisation:mcq:57e33408', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which is the best definition of globalisation?", "options": ["A rise in a country''s exchange rate", "A country''s total exports minus imports", "The growing interconnectedness and interdependence of the world''s economies", "The total value of goods produced in one year"]}'::jsonb, '{"answer": 2, "explain": "Globalisation is the growing interconnectedness and interdependence of economies worldwide, driven by trade, investment, migration and flows of technology across borders."}'::jsonb),
('economics:4-4-globalisation:mcq:fda8e6b1', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of these is a driving factor of globalisation?", "options": ["Containerisation of shipping", "Higher tariffs on imported goods", "Restrictions on foreign investment", "Rising transport costs"]}'::jsonb, '{"answer": 0, "explain": "Containerisation let container ships grow massively in size, giving huge economies of scale and cutting shipping costs — one of the biggest drivers of globalisation. The other three options would all SLOW globalisation."}'::jsonb),
('economics:4-4-globalisation:mcq:5db33cc9', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "The Human Development Index (HDI) combines GDP per capita, education and...", "options": ["The exchange rate", "Life expectancy", "The rate of inflation", "Carbon emissions"]}'::jsonb, '{"answer": 1, "explain": "The HDI is a composite of three factors: income (GDP per capita), education and life expectancy — built to give a fuller picture of development than income alone."}'::jsonb),
('economics:4-4-globalisation:mcq:340e348c', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "A country''s HDI score is much higher than its Inequality-adjusted HDI (IHDI) score. What does this suggest?", "options": ["The country has very low inequality", "The country''s GDP per capita has fallen", "The country has significant inequality in income, health or education", "The country has a falling population"]}'::jsonb, '{"answer": 2, "explain": "A large gap between HDI and IHDI means the average outcomes hide a lot of inequality — some people are doing far better, or worse, than the headline HDI score suggests."}'::jsonb),
('economics:4-4-globalisation:mcq:3947d067', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which is most likely to be a BENEFIT of globalisation for PRODUCERS in a developed country?", "options": ["Exposure to demand slowdowns abroad", "Access to cheaper imported inputs and larger export markets", "Job losses in declining industries", "Increased competition from overseas firms"]}'::jsonb, '{"answer": 1, "explain": "Cheaper imported inputs and access to larger markets (economies of scale) are benefits. Increased competition and exposure to foreign demand slowdowns are costs, and job losses affect workers, not producers directly."}'::jsonb),
('economics:4-4-globalisation:mcq:22de718d', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which is a genuine COST of globalisation for WORKERS in a developed country?", "options": ["Access to a wider variety of goods", "More jobs as firms grow to serve larger markets", "Job insecurity during global demand slowdowns", "Greater freedom to work abroad"]}'::jsonb, '{"answer": 2, "explain": "Job insecurity during global slowdowns is a real cost for workers whose jobs depend on international demand. The other options are benefits, and ''wider variety of goods'' is a benefit for consumers, not workers."}'::jsonb),
('economics:4-4-globalisation:mcq:a3f70308', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "What is meant by the ''brain drain'' in a less developed country?", "options": ["A fall in a country''s exchange rate", "Skilled workers, such as doctors, migrating abroad for higher pay", "Automation replacing manual workers", "Firms relocating factories to cheaper countries"]}'::jsonb, '{"answer": 1, "explain": "The brain drain describes skilled or educated workers leaving a less developed country for better pay or living conditions elsewhere, reducing the supply of skilled labour at home."}'::jsonb),
('economics:4-4-globalisation:mcq:d802357b', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "Rising global demand for a less developed country''s exports, without a matching rise in supply, is most likely to cause...", "options": ["A fall in GDP per capita", "Demand-pull inflation", "Deflation", "Lower exchange rates"]}'::jsonb, '{"answer": 1, "explain": "If supply can''t keep up with rising demand from globalisation, prices are bid up — demand-pull inflation. This is especially serious for essential goods like basic foodstuffs in LDCs."}'::jsonb),
('economics:4-4-globalisation:mcq:a1958b46', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of environmental UNsustainability linked to globalisation?", "options": ["A firm relocating production to a country with weaker environmental laws", "A firm investing in renewable energy", "A firm using more efficient specialised production", "A government taxing carbon emissions"]}'::jsonb, '{"answer": 0, "explain": "Firms sometimes relocate production partly BECAUSE environmental laws are weaker elsewhere, which can cause significant environmental damage in the host country — a real cost of globalisation."}'::jsonb),
('economics:4-4-globalisation:mcq:3b4236e0', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'mcq', 'mcq', 1, '{"question": "In a less developed country, why does the gap between rich and poor tend to WIDEN as a result of globalisation?", "options": ["Because much of the extra profit from trade is kept by business owners rather than workers", "Because exports always fall", "Because tariffs always rise", "Because GDP per capita always falls"]}'::jsonb, '{"answer": 0, "explain": "Even though globalisation can create jobs and raise incomes overall, much of the extra profit from globalisation-driven trade tends to be kept by business owners, widening inequality between rich and poor."}'::jsonb),
('economics:4-4-globalisation:tf:0a457857', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "Globalisation is a purely modern phenomenon that only began in the last 20 years."}'::jsonb, '{"answer": false, "explain": "International trade has existed for centuries. What''s new is the SCALE and SPEED enabled by modern transport and communications technology — not the existence of trade itself."}'::jsonb),
('economics:4-4-globalisation:tf:0784b1e8', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "Containerisation is one of the biggest driving factors of globalisation."}'::jsonb, '{"answer": true, "explain": "Standard-size containers moved between ships, trains and trucks let container ships grow massively, giving huge economies of scale and much lower shipping costs."}'::jsonb),
('economics:4-4-globalisation:tf:c66a4c74', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "GDP per capita alone shows exactly how income is distributed within a country."}'::jsonb, '{"answer": false, "explain": "GDP per capita is only an AVERAGE. It says nothing about distribution — a country can have high GDP per capita while most income sits with a small rich minority."}'::jsonb),
('economics:4-4-globalisation:tf:496d1d48', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "The Human Development Index (HDI) combines income, life expectancy and education."}'::jsonb, '{"answer": true, "explain": "The HDI is a composite measure built by the United Nations specifically to combine these three factors, overcoming the limitation of using GDP per capita alone."}'::jsonb),
('economics:4-4-globalisation:tf:86fa2346', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "Globalisation only benefits large, rich countries."}'::jsonb, '{"answer": false, "explain": "Globalisation can also drive rapid growth and poverty reduction in developing economies that attract investment and export industries — though the benefits are not evenly shared."}'::jsonb),
('economics:4-4-globalisation:tf:a2d2552e', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "The brain drain makes it EASIER for producers in a less developed country to hire skilled workers."}'::jsonb, '{"answer": false, "explain": "The opposite: the brain drain is skilled workers LEAVING for higher pay abroad, making it HARDER for domestic producers to hire and retain skilled labour."}'::jsonb),
('economics:4-4-globalisation:tf:7b1f423b', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "Homogenisation is a cost of globalisation for consumers in developed countries."}'::jsonb, '{"answer": true, "explain": "As large international brands out-compete smaller local firms, shopping experiences become increasingly similar across countries — a real cost, even though prices may fall."}'::jsonb),
('economics:4-4-globalisation:tf:11315345', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tf', 'tf', 1, '{"question": "In less developed countries, the rich-poor gap typically narrows as a result of globalisation."}'::jsonb, '{"answer": false, "explain": "It typically WIDENS — much of the extra profit from globalisation-driven trade is often kept by business owners rather than passed on to workers."}'::jsonb),
('economics:4-4-globalisation:learn:90869e4d', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Globalisation and its driving factors", "reading": "<p><strong>Globalisation is the growing interconnectedness and interdependence of the world''s economies</strong>, driven by increased trade, investment, migration and flows of information and technology across borders. A modern smartphone might be manufactured using parts sourced from five or six different countries — a small example of a very large trend.</p>\n<h4>Roots of large-scale globalisation</h4>\n<ul>\n<li>Traces back to the <strong>end of the Second World War</strong> — a shortage of goods pushed nations to trade and cooperate to make the most of scarce resources.</li>\n<li>The creation of the <strong>United Nations</strong> encouraged greater cultural exchange as nations sought to avoid another world war.</li>\n<li>More recently, <strong>China opening up to Western trade</strong> hugely increased world trade, given the size of its population.</li>\n<li><strong>Common misconception:</strong> globalisation is NOT a purely modern phenomenon — international trade has existed for centuries. What''s new is the SCALE and SPEED enabled by modern transport and technology.</li>\n</ul>\n<h4>The driving factors — learn all four, with an example for each</h4>\n<ul>\n<li><strong>Improved transport</strong> — cheaper, faster shipping and air freight. <strong>Containerisation</strong> (standard-size containers movable between ships, trains and trucks) is probably the single biggest contributor: container ships have grown massively in size, giving huge economies of scale and much lower shipping costs.</li>\n<li><strong>Improved communications technology</strong> — the internet and mobile networks make it easy to coordinate global supply chains and sell directly to consumers in other countries.</li>\n<li><strong>Trade liberalisation</strong> — the reduction of tariffs and trade barriers via agreements and organisations such as the World Trade Organisation, and the expansion of free-trade areas and customs unions (less form-filling and fewer customs checks).</li>\n<li><strong>Growth of multinational companies (MNCs) and foreign direct investment (FDI)</strong> — many countries have relaxed rules on foreign ownership since WWII, so firms increasingly build factories and offices in multiple countries, seeking lower costs, new markets or access to resources. Most FDI into the UK comes from the USA.</li>\n</ul>\n<h4>Scale of globalisation — real numbers</h4>\n<ul>\n<li>UK exports plus imports totalled just <strong>£159,565 million in 1983</strong>, but <strong>£1,257,706 million by 2017</strong> — roughly an eightfold increase, showing how significant globalisation has been for the UK economy.</li>\n</ul>", "question": "Which of these is the single biggest transport-related driver of globalisation?", "options": ["Slower freight trains", "Containerisation of shipping", "Higher airport taxes", "Reduced use of ports"]}'::jsonb, '{"answer": 1, "explain": "Standard-size containers moving between ships, trains and trucks allowed container ships to grow massively, giving huge economies of scale and cutting the cost of shipping goods internationally."}'::jsonb),
('economics:4-4-globalisation:learn:eff5e3fa', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "How development is measured", "reading": "<p><strong>GDP per capita</strong> (total GDP divided by population) is the most commonly used single measure of development — because output produced is income earned by the people who produce it, higher average income generally means people have more to spend, suggesting a more developed country.</p>\n<h4>The limitation of GDP per capita alone</h4>\n<ul>\n<li>It is only an AVERAGE — it says nothing about how income is actually distributed. A country can have a high GDP per capita while most of that income sits with a small rich minority.</li>\n<li><strong>Misconception to avoid:</strong> GDP per capita is not measured \"by household, family or region\" — it is total GDP divided by the WHOLE national population.</li>\n</ul>\n<h4>The Human Development Index (HDI)</h4>\n<ul>\n<li>Developed by the <strong>United Nations</strong>, the HDI is a COMPOSITE measure combining three factors: <strong>1. GDP per capita (income), 2. Life expectancy, 3. Education</strong> — built specifically to overcome the limitation of using income alone.</li>\n<li><strong>Life expectancy</strong> is affected by access to and affordability of healthcare, exposure to violent political conflict, and exposure to environmental issues such as drought, famine or flood.</li>\n<li><strong>Education</strong> is affected by years spent in education (which affects literacy and productivity), quality of education (facilities, technology, teacher-to-pupil ratios), and access to technology (mobile phone ownership, internet access).</li>\n</ul>\n<h4>The Inequality-adjusted HDI (IHDI)</h4>\n<ul>\n<li>The IHDI adjusts the standard HDI to account for <strong>inequality</strong> in health, education and income within a country.</li>\n<li>A SMALL gap between HDI and IHDI = low inequality. A LARGE gap = high inequality — some people are doing far better (or worse) than the average HDI score suggests.</li>\n</ul>\n<h4>Other measures worth naming</h4>\n<ul>\n<li>Access to health care, access to technology, and access to education can all be cited individually as \"ways of measuring how developed a country is\" in short-answer questions.</li>\n</ul>", "question": "Why was the Human Development Index (HDI) created?", "options": ["To replace life expectancy as a statistic", "To combine income, life expectancy and education, since GDP per capita alone doesn''t show the full picture", "To measure inequality only", "To measure a country''s exports only"]}'::jsonb, '{"answer": 1, "explain": "GDP per capita alone only shows average income. The HDI was built specifically to combine it with life expectancy and education, giving a fuller picture of development."}'::jsonb),
('economics:4-4-globalisation:learn:1dd2c97f', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Globalisation in developed countries", "reading": "<p>The spec asks you to evaluate costs and benefits for <strong>producers, workers and consumers</strong> separately — questions name one, and answering about the wrong group is not awardable.</p>\n<h4>Producers</h4>\n<ul>\n<li><strong>Benefits:</strong> access to more markets/customers so firms can exploit economies of scale; access to better-quality or cheaper imported inputs; access to more skilled (often cheaper) labour migrating from less developed countries; easier shared research and development with firms overseas.</li>\n<li><strong>Costs:</strong> more competition from overseas firms — some domestic industries lose competitive advantage; firms that have grown large to serve foreign markets become more exposed to demand slowdowns in those markets.</li>\n</ul>\n<h4>Workers</h4>\n<ul>\n<li><strong>Benefits:</strong> more jobs as firms grow to serve larger markets; more foreign investment creates additional jobs; greater freedom to work in other countries.</li>\n<li><strong>Costs:</strong> workers in declining industries may lack the skills to move into new industries, risking long-term unemployment; risk of job losses through automation as firms cut costs to stay competitive; job insecurity during global demand slowdowns; immigration can increase competition for jobs, helping keep wages low.</li>\n</ul>\n<h4>Consumers</h4>\n<ul>\n<li><strong>Benefits:</strong> greater choice of products worldwide; cheaper products, leaving more disposable income; skilled migration improves services (e.g. the NHS recruits many doctors and nurses from less developed countries); fewer travel restrictions.</li>\n<li><strong>Costs:</strong> <strong>homogenisation</strong> — large international firms out-compete smaller local firms, so shopping experiences become very similar across countries; <strong>price volatility</strong> from globalised markets, e.g. the pandemic and the war in Ukraine both caused significant supply disruption.</li>\n</ul>\n<h4>The three sustainabilities for developed countries</h4>\n<ul>\n<li><strong>Economic:</strong> generally improves — greater specialisation lowers costs and input prices.</li>\n<li><strong>Social:</strong> mixed — lower prices can improve quality of life, but many of the UK''s poorest, most deprived areas are that way because of industries that declined due to globalisation.</li>\n<li><strong>Environmental:</strong> mixed — more efficient specialised production, but increased fossil fuel use transporting goods globally, and firms may shift production to countries with weaker environmental protections.</li>\n</ul>", "question": "Which is a genuine COST of globalisation for CONSUMERS in a developed country?", "options": ["Greater product choice", "Homogenisation of shopping experiences as global brands dominate", "Cheaper products", "Fewer travel restrictions"]}'::jsonb, '{"answer": 1, "explain": "Homogenisation is a real cost for consumers — large international firms out-compete smaller local ones, so shops and products look increasingly similar wherever you are. The other three are benefits, not costs."}'::jsonb),
('economics:4-4-globalisation:learn:58d6f5f8', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Globalisation in less developed countries", "reading": "<p>The same three stakeholder groups apply, but with different — and more mixed — effects in less developed countries (LDCs).</p>\n<h4>Producers</h4>\n<ul>\n<li><strong>Benefits:</strong> access to more markets/customers; opportunity to adopt new technologies, raising productivity and lowering average costs; ability to attract increased foreign investment, supporting growth and economies of scale.</li>\n<li><strong>Costs:</strong> vulnerability to global slowdowns, since production is aimed at international markets; difficulty hiring/retaining skilled labour due to the <strong>\"brain drain\"</strong> — people educated in LDCs move abroad for higher pay; small domestic businesses can struggle once large international firms enter the market.</li>\n</ul>\n<h4>Workers</h4>\n<ul>\n<li><strong>Benefits:</strong> greater trade and higher output generally require more workers; increased foreign investment creates more jobs; skilled workers can seek opportunities abroad (though most developed countries'' immigration policies mean this route is largely open only to SKILLED workers).</li>\n<li><strong>Costs:</strong> automation used to meet rising global demand can cause job losses; exposure to job losses during global demand slowdowns; worse working conditions than would be tolerated in developed nations; much of the extra profit is often kept by business owners, widening the rich-poor gap.</li>\n</ul>\n<h4>Consumers</h4>\n<ul>\n<li><strong>Benefits:</strong> greater choice and more opportunities to travel — though this depends heavily on income; improved infrastructure (roads, rail) as a side effect of globalisation-driven investment.</li>\n<li><strong>Costs:</strong> if supply cannot keep pace with extra demand, <strong>demand-pull inflation</strong> can result — especially serious for essential goods like basic foodstuffs; the brain drain reduces the number of skilled professionals (e.g. doctors) available domestically.</li>\n</ul>\n<h4>The three sustainabilities for LDCs</h4>\n<ul>\n<li><strong>Economic:</strong> more jobs and trade create a cycle of growth, but sustainability depends on whether the country KEEPS its competitive advantage and whether growth relies on non-renewable resources.</li>\n<li><strong>Social:</strong> increased income can reduce overall poverty, but the rich-poor gap tends to WIDEN, and rising prices from increased global demand hit the poor hardest — potentially causing malnutrition.</li>\n<li><strong>Environmental:</strong> more efficient use of finite resources is generally positive, but pollution from transporting goods increases, and firms often relocate to LDCs partly BECAUSE of weaker environmental laws.</li>\n</ul>\n", "question": "What is the ''brain drain'' a cost of, for producers in less developed countries?", "options": ["Rising carbon emissions", "Losing skilled workers who move abroad for higher pay", "Falling exchange rates", "Increased tariffs on imports"]}'::jsonb, '{"answer": 1, "explain": "The brain drain is when people educated in a less developed country move abroad for higher pay or better living conditions, making it harder for domestic producers to hire and retain skilled labour."}'::jsonb),
('economics:4-4-globalisation:misc:3a3bdd59', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"GDP per capita measures how evenly income is spread across a country''s population.\"</p><p><strong>✅ The correct idea:</strong> This is a documented examiner misconception on this exact paper. The mark scheme for Q2(i) — explaining why GDP per capita measures development in Tanzania — states directly: \"A common misconception is confusion between GDP per capita as an average and wealth or income distribution which is a different concept. Furthermore, some candidates believed GDP per capita was by household, family or region.\" GDP per capita is total GDP divided by the WHOLE national population — an AVERAGE. It says nothing about how that income is actually shared out; a country can have a high GDP per capita while most of the income sits with a small rich minority. Income DISTRIBUTION (equality) is a separate macroeconomic concept entirely.</p>", "question": "What is the key misconception examiners reported about GDP per capita?", "options": ["That it excludes services", "Confusing it with income distribution, or believing it is measured by household/family/region", "That it can never fall", "That it is measured monthly, not annually"]}'::jsonb, '{"answer": 1, "explain": "The mark scheme''s own words: candidates confused GDP per capita (an AVERAGE) with income distribution (a different concept), and some wrongly thought it was measured by household, family or region rather than for the whole country."}'::jsonb),
('economics:4-4-globalisation:misc:ce530b0d', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The question asks about workers, but I''ll write about benefits to the economy in general — it''s basically the same thing.\"</p><p><strong>✅ The correct idea:</strong> It is NOT the same thing, and this paper punishes it directly. On Q2(iii) — ''Evaluate the benefits of globalisation for WORKERS in Tanzania'' — the examiner''s comments state plainly: \"some candidates wrote about benefits to the economy in general or other stakeholders which was not awardable.\" The same trap appears again on Q19(iii), which asks specifically about consumers in LDCs: the mark scheme''s own N.B. warns \"this question is specifically on the impact on consumers in LDCs so impacts solely on producers or workers is not relevant.\" This is the single biggest theme on this paper — whenever a question names a stakeholder (workers / producers / consumers, and often a specific country), an answer about a different group scores ZERO on that point, no matter how good the economics is.</p>", "question": "A question asks you to evaluate the benefits of globalisation for WORKERS in a named country. What happens if you write about benefits to the wider economy instead?", "options": ["You get half marks automatically", "The examiner assumes you meant workers", "You get full marks anyway, since it''s related", "That material is not awardable — you must answer for the exact stakeholder named"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme is explicit on this paper: writing about the economy in general, or about a different stakeholder, when the question names one group specifically, is ''not awardable''."}'::jsonb),
('economics:4-4-globalisation:misc:c278eaec', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The biggest cost of globalisation for consumers in developed countries is increased immigration.\"</p><p><strong>✅ The correct idea:</strong> This is a documented examiner misconception on Q3 of this exact paper (\"What is the most likely cost of globalisation for consumers in developed countries?\"). The correct answer is A — dominant global brands — not immigration. The examiner''s comments state: \"A common misconception was increased immigration was a cost of globalisation, rather than the more likely negative impact of dominant global brands.\" Dominant global brands reduce genuine variety and out-compete smaller, often more distinctive local firms — this is the effect known as homogenisation. Immigration is a labour-market issue for WORKERS, not a direct cost for consumers.</p>", "question": "According to this paper''s mark scheme, what is the most likely COST of globalisation for consumers in developed countries?", "options": ["Lower prices", "More choice of goods", "Increased immigration", "Dominant global brands"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme names dominant global brands as the correct answer, and flags increased immigration as the common wrong answer — immigration is a labour-market issue, not a direct consumer cost."}'::jsonb),
('economics:4-4-globalisation:misc:04ef3d72', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Free trade agreements are a cost to producers because there is more competition.\" (and stops there)</p><p><strong>✅ The correct idea:</strong> Stating a cost is only worth 1 of the 2 marks on this paper''s short ''explain'' questions — you must EXPLAIN it. On Q15(ii) (''Explain one cost to producers of globalisation''), the mark scheme awards \"1 mark for stating a cost which is not explained\" and \"2 marks for providing an explained cost.\" The examiner''s comments confirm this actually cost candidates marks: \"This question was generally answered well, although some candidates stated a cost, rather than explaining it.\" The fix is a simple chain: state the cost, then add WHY it happens or WHAT it leads to — e.g. ''more competition from lower-cost overseas producers (1), which may be harmful to domestic producers whose productivity is lower (1)''.</p>", "question": "On a 2-mark ''explain one cost'' question, writing only ''more competition'' with no further development scores...", "options": ["0 marks — costs are not creditable", "2 marks, as long as it''s true", "2 marks — the cost is correct", "1 mark — a stated but unexplained cost"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme is explicit: 1 mark for stating a cost without explanation, 2 marks only when the cost is properly explained (why it happens, or what it leads to)."}'::jsonb),
('economics:4-4-globalisation:misc:dae17a32', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"State two trends in university enrolment\" — answered by comparing Burkina Faso and China to each other.</p><p><strong>✅ The correct idea:</strong> A comparison is not a trend, and this cost real marks on Q14(a) of this paper. The examiner''s comments explain precisely: \"The key was that the response needed a ''TREND'' rather than a comparison (between BF and China). It also needed to focus on university enrolment rather than any of the other data in the table.\" A TREND describes how a single variable changes over TIME within one series (e.g. ''female university enrolment in Burkina Faso rose from 2.3% to 5.1% between 2010 and 2019''). A COMPARISON instead contrasts two different series at one point in time (e.g. ''China''s enrolment is higher than Burkina Faso''s'') — that is a different command entirely, and the wrong answer to a ''state two trends'' question.</p>", "question": "A question asks you to ''state two trends'' in a data table covering two countries over several years. What must your answer describe?", "options": ["Only the most recent year''s figures", "How a variable changes over time within one series", "The largest single number in the table", "A comparison between the two countries"]}'::jsonb, '{"answer": 1, "explain": "A trend tracks change over TIME. Comparing the two countries to each other, however accurate, answers a different question and was explicitly marked as not creditable here."}'::jsonb),
('economics:4-4-globalisation:tips:d664ebc4', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "definition — Definitions: name the required elements", "reading": "<p>Short-answer definitions on this paper are marked element by element — learn the PRECISE wording, not just the gist.</p>\n<ul>\n<li><strong>Globalisation</strong> = the mark scheme accepts any TWO of: greater freedom of movement between countries; free movement of goods, services, people and money; the expansion of world trade in goods and services; the expansion of capital flows between countries; greater international interdependence. One element = 1 mark.</li>\n<li><strong>Free trade agreement</strong> needs TWO elements: no import tariffs/quotas between member countries (1), PLUS that members can still trade freely with countries outside the group, or a correct example such as NAFTA/EFTA (1).</li>\n<li><strong>GDP per capita</strong> = total value of output/income in a country in one year, divided by the population. A bare \"GDP divided by population\" without saying what GDP measures is only worth 1 of 2 marks.</li>\n<li><strong>Ways of measuring development</strong> — 1 mark each: GDP (per capita), life expectancy, access to health care, access to technology, access to education.</li>\n</ul>", "question": "For ''state what is meant by globalisation'', how many separate elements does the mark scheme require for full marks?", "options": ["Two", "Three", "Four", "One"]}'::jsonb, '{"answer": 0, "explain": "The mark scheme gives 2 marks for a definition referring to at least two of its listed elements (free movement of goods/services/people/money, expansion of trade, expansion of capital flows, greater interdependence)."}'::jsonb),
('economics:4-4-globalisation:tips:9a9dd9df', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "stakeholder — Name the stakeholder — or score nothing", "reading": "<p>This is the single most-repeated trap across the whole paper. Every extended question names a specific group — and answering about a different one is explicitly NOT awardable.</p>\n<ul>\n<li>Q2(iii) asks about <strong>WORKERS</strong> in Tanzania. The examiner''s comments say some candidates \"wrote about benefits to the economy in general or other stakeholders which was not awardable.\"</li>\n<li>Q19(iii) asks about <strong>CONSUMERS</strong> in LDCs. The mark scheme''s N.B. states: \"impacts solely on producers or workers is not relevant.\"</li>\n<li>Q7(d)(iii) asks about <strong>US PRODUCERS</strong>. The examiner''s comments note candidates who wrote about \"the economy in general\" or \"the effects of globalisation on households or the government\" could \"only be partially rewarded at best.\"</li>\n<li><strong>Fix:</strong> before writing a single sentence, underline the named group in the question. Every analytical point AND its matching evaluative point must trace back to that exact group.</li>\n</ul>", "question": "A 6-mark question asks you to evaluate the benefits of globalisation for CONSUMERS in a less developed country. Which answer content is NOT awardable?", "options": ["A point about producers losing skilled workers to the brain drain", "A point about consumers paying higher prices for food", "A point evaluating whether price rises outweigh the wider choice", "A point about consumers accessing a wider range of goods"]}'::jsonb, '{"answer": 0, "explain": "A point about PRODUCERS losing workers answers a different question. The mark scheme explicitly excludes stakeholder-swap content — every point must be about the group actually named."}'::jsonb),
('economics:4-4-globalisation:tips:0bbe68bb', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "calculation — Calculations: show working, keep the sign and the unit", "reading": "<p>Every calculation on this paper follows the same pattern: 2 marks for a correct final answer (working not required if correct), 1 mark for correct working with a wrong final answer.</p>\n<ul>\n<li><strong>Balance of trade in goods and services</strong> = balance of trade in goods + balance of trade in services. For the US in 2019: −924,284 + 286,723 = <strong>−$637,561 million</strong>. The examiners noted candidates lost marks by omitting the $ sign, \"million\", or the negative sign.</li>\n<li><strong>GDP per capita</strong> = GDP ÷ population. For Burkina Faso in 2019: $15,700 million ÷ 20.3 million = <strong>$773.4</strong>. The examiners noted: \"1 mark only if $ sign is omitted\" — units matter even when the number is right.</li>\n<li><strong>Simple differences</strong> (e.g. Sweden''s GDP per capita minus Botswana''s) still need 1 mark for correct working and 1 for the final figure — set your subtraction out clearly.</li>\n</ul>", "question": "You correctly calculate a GDP per capita of 773.4 but forget the $ sign. According to this paper''s mark scheme, you would score...", "options": ["2 marks — the figure is correct", "0 marks — the answer is void without units", "2 marks, as signs are optional", "1 mark — correct working/figure but a missing required sign"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme is explicit: full marks require the correct figure AND the correct sign/unit. A missing $ sign caps the answer at 1 mark even when the number itself is right."}'::jsonb),
('economics:4-4-globalisation:tips:a2ac7938', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Analyse & Evaluate: both costs AND benefits for Level 3", "reading": "<p>The extended 6-mark questions reward simple, clearly linked chains of reasoning far more than long, unfocused answers.</p>\n<ul>\n<li><strong>Cover both sides.</strong> On Q7(d)(iii) the mark scheme states plainly: \"Both costs & benefits need to be covered in order to achieve Level 3.\" A one-sided answer is capped, however detailed.</li>\n<li><strong>Match your evaluation to your analysis.</strong> The most common way marks are lost is writing an analytical point, then \"evaluating\" with an unrelated new point instead of directly weighing the first one.</li>\n<li><strong>Build a proper chain, don''t just restate data.</strong> On Q7(c) examiners warned against candidates who \"re-write the information in Extract 3 without any analysis\" — e.g. simply repeating \"the economy becomes less based on domestic manufacturing\" without explaining WHY or WHAT FOLLOWS.</li>\n<li><strong>Signal your judgement clearly</strong> with words like \"Overall\" or \"In conclusion\" — evaluation signalled only by \"However\" sometimes turned out to be an unlinked extra point rather than a real weighing-up.</li>\n</ul>", "question": "According to this paper''s mark scheme, what is required to reach Level 3 (5–6 marks) on a 6-mark ''evaluate the extent to which...'' question?", "options": ["Only costs need to be discussed", "Both costs and benefits must be covered", "As much data as possible must be quoted", "Only benefits need to be discussed"]}'::jsonb, '{"answer": 1, "explain": "The mark scheme for Q7(d)(iii) states directly that both costs and benefits need to be covered to achieve Level 3 — a one-sided answer, however well written, is capped at a lower level."}'::jsonb),
('economics:4-4-globalisation:fib:3cc231e8', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'fib', 'fib', 2, '{"question": "Globalisation is the growing ___B1___ and interdependence of the world''s ___B2___.", "blankOptions": {"B1": ["trade", "capital", "interconnectedness", "brain"], "B2": ["driving", "demand", "economies", "inflation"]}}'::jsonb, '{"blanks": {"B1": "interconnectedness", "B2": "economies"}}'::jsonb),
