('economics:4-4-globalisation:fib:f79cd7f5', 'economics', 'economics:4-4-globalisation', '4.4 Globalisation', 'fib', 'fib', 2, '{"question": "A large gap between a country''s HDI and its Inequality-adjusted HDI shows a high level of ___B1___ in income, health or ___B2___.", "blankOptions": {"B1": ["tariffs", "inequality", "Containerisation", "brain"], "B2": ["Containerisation", "inflation", "Index", "education"]}}'::jsonb, '{"blanks": {"B1": "inequality", "B2": "education"}}'::jsonb),
